static int words_compare(const uint32_t *a,const uint32_t *b) { for(int i=RSA_WORDS-1;i>=0;i--){if(a[i]>b[i])return 1;if(a[i]<b[i])return -1;}return 0; }
static void add_mod(uint32_t *out,const uint32_t *a,const uint32_t *b,const uint32_t *n) {
  uint32_t t[RSA_WORDS];uint64_t carry=0;
  for(unsigned i=0;i<RSA_WORDS;i++){uint64_t v=(uint64_t)a[i]+b[i]+carry;t[i]=(uint32_t)v;carry=v>>32;}
  if(carry||words_compare(t,n)>=0){uint64_t borrow=0;for(unsigned i=0;i<RSA_WORDS;i++){uint64_t before=t[i],sub=(uint64_t)n[i]+borrow;t[i]=(uint32_t)(before-sub);borrow=before<sub;}}
  for(unsigned i=0;i<RSA_WORDS;i++)out[i]=t[i];
}
static void multiply_mod(uint32_t *out,const uint32_t *a,const uint32_t *b,const uint32_t *n) {
  uint32_t result[RSA_WORDS]={0},power[RSA_WORDS];for(unsigned i=0;i<RSA_WORDS;i++)power[i]=a[i];
  for(unsigned bit=0;bit<2048;bit++){if((b[bit/32]>>(bit%32))&1U)add_mod(result,result,power,n);add_mod(power,power,power,n);}
  for(unsigned i=0;i<RSA_WORDS;i++)out[i]=result[i];
}
static void from_big_endian(uint32_t out[RSA_WORDS],const uint8_t in[256]) { for(unsigned word=0;word<RSA_WORDS;word++){unsigned p=256-4*(word+1);out[word]=((uint32_t)in[p]<<24)|((uint32_t)in[p+1]<<16)|((uint32_t)in[p+2]<<8)|in[p+3];} }
int aiueos_rsa2048_sha256_verify(const uint8_t signature[256],const uint8_t digest[32]) {
  uint32_t n[RSA_WORDS],base[RSA_WORDS],result[RSA_WORDS]={0},temporary[RSA_WORDS];
  uint8_t encoded[256],difference=0;from_big_endian(n,rsa_modulus_bytes);from_big_endian(base,signature);
  if(words_compare(base,n)>=0)return 0;result[0]=1;
  for(int bit=16;bit>=0;bit--){multiply_mod(temporary,result,result,n);for(unsigned i=0;i<RSA_WORDS;i++)result[i]=temporary[i];if(bit==16||bit==0){multiply_mod(temporary,result,base,n);for(unsigned i=0;i<RSA_WORDS;i++)result[i]=temporary[i];}}
  for(unsigned word=0;word<RSA_WORDS;word++){uint32_t v=result[word];unsigned p=256-4*(word+1);encoded[p]=v>>24;encoded[p+1]=v>>16;encoded[p+2]=v>>8;encoded[p+3]=v;}
  static const uint8_t prefix[19]={0x30,0x31,0x30,0x0d,0x06,0x09,0x60,0x86,0x48,0x01,0x65,0x03,0x04,0x02,0x01,0x05,0x00,0x04,0x20};
  difference|=encoded[0];difference|=encoded[1]^1;for(unsigned i=2;i<204;i++)difference|=encoded[i]^0xff;difference|=encoded[204];for(unsigned i=0;i<19;i++)difference|=encoded[205+i]^prefix[i];for(unsigned i=0;i<32;i++)difference|=encoded[224+i]^digest[i];
  return difference==0;
}
